    @SubscribeEvent
    public static void onEntityJoinLevel(EntityJoinLevelEvent event) {
        if (event.getLevel().isClientSide) return;
        if (!(event.getEntity() instanceof Projectile projectile)) return;
        if (projectile.getTags().contains("shotgun_generated")) return;
        Entity owner = projectile.getOwner();
        if (!(owner instanceof LivingEntity shooter)) return;
        int level = 0;
        if (EnchantmentHelper.getItemEnchantmentLevel(ModEnchantments.MAGIC_SHOTGUN.get(), shooter.getMainHandItem()) > 0)
            level = EnchantmentHelper.getItemEnchantmentLevel(ModEnchantments.MAGIC_SHOTGUN.get(), shooter.getMainHandItem());
        else if (EnchantmentHelper.getItemEnchantmentLevel(ModEnchantments.MAGIC_SHOTGUN.get(), shooter.getOffhandItem()) > 0)
            level = EnchantmentHelper.getItemEnchantmentLevel(ModEnchantments.MAGIC_SHOTGUN.get(), shooter.getOffhandItem());
        if (level > 0) spawnShotgunProjectiles(projectile, shooter, level * 10, event.getLevel());
    }

    private static void spawnShotgunProjectiles(Projectile original, LivingEntity shooter, int count, Level level) {
        CompoundTag tag = new CompoundTag(); original.saveWithoutId(tag); tag.remove("UUID");
        for (int i = 0; i < count; i++) {
            Entity newEntity = original.getType().create(level);
            if (!(newEntity instanceof Projectile np)) continue;
            np.load(tag); np.setPos(original.getX(), original.getY(), original.getZ()); np.setOwner(shooter);
            Vec3 v = original.getDeltaMovement(); double sp = v.length();
            double spread = 0.1 + level.random.nextDouble() * 0.05;
            np.setDeltaMovement(v.normalize().add(
                (level.random.nextDouble()-0.5)*spread,
                (level.random.nextDouble()-0.5)*spread,
                (level.random.nextDouble()-0.5)*spread).normalize().scale(sp));
            if (np instanceof AbstractArrow aa) aa.pickup = AbstractArrow.Pickup.DISALLOWED;
            np.addTag("shotgun_generated"); level.addFreshEntity(np);
        }
    }

    @SubscribeEvent
    public static void onMobEffectAdded(MobEffectEvent.Added event) {
        LivingEntity entity = event.getEntity();
        if (entity.level().isClientSide()) return;
        if (PROCESSING_EFFECT_MULTIPLY.contains(entity.getUUID())) return;
        var emEffect = entity.getEffect(ModMobEffects.EFFECT_MULTIPLY.get());
        if (emEffect == null) return;
        var incoming = event.getEffectInstance();
        if (incoming == null || incoming.getEffect() == ModMobEffects.EFFECT_MULTIPLY.get()) return;
        if (incoming.getEffect().getCategory() != net.minecraft.world.effect.MobEffectCategory.HARMFUL) return;
        int newDuration = (int)(incoming.getDuration() * EffectMultiplyEffect.getMultiplier(emEffect.getAmplifier()));
        PENDING_EFFECT_EXTENSIONS.computeIfAbsent(entity.getUUID(), k -> new java.util.ArrayList<>())
            .add(new MobEffectInstance(incoming.getEffect(), newDuration, incoming.getAmplifier(),
                    incoming.isAmbient(), incoming.isVisible(), incoming.showIcon()));
    }

