    @SubscribeEvent
    public static void onLivingEntityUseItemStart(LivingEntityUseItemEvent.Start event) {
        if (TimeStopFieldEntity.isFrozenByActiveField(event.getEntity().level(), event.getEntity())) {
            event.setCanceled(true);
        }
    }

    @SubscribeEvent
    public static void onLivingEntityUseItemTick(LivingEntityUseItemEvent.Tick event) {
        if (TimeStopFieldEntity.isFrozenByActiveField(event.getEntity().level(), event.getEntity())) {
            event.setCanceled(true);
        }
    }

    @SubscribeEvent
    public static void onLivingEntityUseItemFinish(LivingEntityUseItemEvent.Finish event) {
        if (TimeStopFieldEntity.isFrozenByActiveField(event.getEntity().level(), event.getEntity())) {
            event.setCanceled(true);
        }
    }

    private static void applyIronsEffect(LivingEntity entity, String name, int duration, int amplifier) {
        MobEffect effect = ForgeRegistries.MOB_EFFECTS.getValue(new ResourceLocation("irons_spellbooks", name));
        if (effect != null) entity.addEffect(new MobEffectInstance(effect, duration, amplifier));
    }

    @SubscribeEvent
    public static void onAnvilUpdate(AnvilUpdateEvent event) {
        ItemStack left = event.getLeft(); ItemStack right = event.getRight();
        if (left.getItem() == ModItems.MAGIC_GUN.get() && right.getItem() == net.minecraft.world.item.Items.ENCHANTED_BOOK) {
            Map<Enchantment, Integer> enchants    = EnchantmentHelper.getEnchantments(right);
            Map<Enchantment, Integer> newEnchants = EnchantmentHelper.getEnchantments(left);
            boolean changed = false;
            for (Map.Entry<Enchantment, Integer> entry : enchants.entrySet()) {
                newEnchants.put(entry.getKey(), entry.getValue()); changed = true;
            }
            if (changed) {
                ItemStack result = left.copy();
                EnchantmentHelper.setEnchantments(newEnchants, result);
                event.setOutput(result); event.setCost(enchants.size()*2+1); event.setMaterialCost(1);
            }
        }
    }

    @SubscribeEvent
    public static void onMobEffectExpired(MobEffectEvent.Expired event) {
        if (event.getEffectInstance() == null) return;
        if (event.getEffectInstance().getEffect() != ModMobEffects.SHOES_OF_DETERMINATION.get()) return;
        LivingEntity entity = event.getEntity();
        if (entity.level().isClientSide()) return;
        java.util.UUID ownerUUID = entity.getUUID();
        entity.level().getEntitiesOfClass(
            com.ecrea.elementmagicboss.entity.projectile.ShoeEntity.class,
            entity.getBoundingBox().inflate(20),
            e -> ownerUUID.equals(e.getOwnerUUID())
        ).forEach(net.minecraft.world.entity.Entity::discard);
    }

    @SubscribeEvent
    public static void onHealingDeterminationExpired(MobEffectEvent.Expired event) {
        if (event.getEffectInstance() == null) return;
        if (event.getEffectInstance().getEffect() != ModMobEffects.HEALING_DETERMINATION.get()) return;
        LivingEntity entity = event.getEntity();
        if (entity.level().isClientSide()) return;
        java.util.UUID ownerUUID = entity.getUUID();
        entity.level().getEntitiesOfClass(
            com.ecrea.elementmagicboss.entity.projectile.HeartOrbitEntity.class,
            entity.getBoundingBox().inflate(10),
            e -> ownerUUID.equals(e.getOwnerUUID())
        ).forEach(net.minecraft.world.entity.Entity::discard);
    }
